( function ( $ ) {'use strict';function igniteCustomFields() {const existing_data = wooIgniteCustomFields.existing_data || {};const field_key = wooIgniteCustomFields.field_key || 'woocommerce_ignite_custom_fields_custom_fields';const default_data = { enabled: 'no', name: '', data: '' };this.custom_field_element_index = '';this.bind_wc_backbone_modal_response_event();// Add button click$( document.body ).on('click','#add_custom_field',function ( e ) {e.preventDefault();let highest = 0;$( '[data-index]' ).each( function () {highest = Math.max( highest, parseFloat( $( this ).attr( 'data-index' ) ) );} );if ( existing_data ) {$.each( existing_data, function ( index, data ) {highest = Math.max( highest, parseFloat( index ) );} );}const index = highest + 1;this.custom_field_add_settings( index, default_data );}.bind( this ));// Delete button click$( document.body ).on('click','.remove_custom_field',function ( e ) {e.preventDefault();this.custom_field_element_index = '';this.custom_field_element_index = $( e.currentTarget ).attr( 'data-index' );$( this ).WCBackboneModal( {template: 'wc-custom-field-modal',} );}.bind( this ));// Input change event to update Save button state$( document.body ).on('input change keyup blur','.ignite-custom-field-name, .ignite-custom-field-data',this.update_save_button_state.bind( this ));// Initial Save button state check - use setTimeout to ensure DOM is readyconst self = this;setTimeout( function() {self.update_save_button_state();}, 100 );}igniteCustomFields.prototype.bind_wc_backbone_modal_response_event = function () {$( document.body ).on( 'wc_backbone_modal_response', this.bind_wc_backbone_modal_response_event_handler.bind( this ) );};igniteCustomFields.prototype.bind_wc_backbone_modal_response_event_handler = function ( e, target ) {if ( target === 'wc-custom-field-modal' ) {$( '#ignite-custom-field-index-' + this.custom_field_element_index ).remove();this.update_save_button_state();}};igniteCustomFields.prototype.update_save_button_state = function () {// Try multiple selectors to find the Save buttonlet $saveButton = $( 'button.button-primary[type="submit"]' );if ( $saveButton.length === 0 ) {$saveButton = $( 'input.button-primary[type="submit"]' );}if ( $saveButton.length === 0 ) {$saveButton = $( '.woocommerce-save-button' );}if ( $saveButton.length === 0 ) {$saveButton = $( 'p.submit .button-primary' );}// Debug: log button search resultsconsole.log( 'Save button found:', $saveButton.length > 0 );if ( $saveButton.length === 0 ) {console.log( 'Save button not found - tried all selectors' );return;}let hasEmptyFields = false;let emptyFieldCount = 0;// Check all Name and Data fields within the custom fields wrapper$( '#ignite-custom-fields-wrapper .ignite-custom-field-name, #ignite-custom-fields-wrapper .ignite-custom-field-data' ).each( function () {const value = $.trim( $( this ).val() );if ( value === '' ) {hasEmptyFields = true;emptyFieldCount++;}} );// Debug: log validation resultsconsole.log( 'Has empty fields:', hasEmptyFields, 'Count:', emptyFieldCount );// Disable/enable Save button based on validationif ( hasEmptyFields ) {$saveButton.prop( 'disabled', true ).addClass( 'disabled' ).css( 'opacity', '0.5' );console.log( 'Save button DISABLED' );} else {$saveButton.prop( 'disabled', false ).removeClass( 'disabled' ).css( 'opacity', '1' );console.log( 'Save button ENABLED' );}};igniteCustomFields.prototype.custom_field_add_settings = function ( index, data ) {const field_element = this.custom_field_create_settings_elements( index, data );$( field_element ).insertBefore( '#add_custom_field' );this.init_tiptip();this.update_save_button_state();};igniteCustomFields.prototype.custom_field_create_settings_elements = function ( index, data ) {const enabled = data.enabled === undefined ? 'no' : data.enabled;const name = data.name === undefined ? '' : data.name;const data_value = data.data === undefined ? '' : data.data;const field_key = wooIgniteCustomFields.field_key || 'woocommerce_ignite_custom_fields_custom_fields';return `<div class="ignite-custom-field" id="ignite-custom-field-index-${ index }" data-index="${ index }"><table class="form-table"><tr valign="top"><th scope="row" class="titledesc" style="width: 20%;"><label>${ wp.i18n.__( 'Enabled', 'woocommerce' ) }</label></th><td class="forminp"><fieldset><legend class="screen-reader-text"><span>${ wp.i18n.__( 'Enabled', 'woocommerce' ) }</span></legend><select class="select ignite-custom-field-enabled" style="width: 100%;" name="${ field_key }[${ index }][enabled]"><option value="no" ${ enabled === 'no' ? 'selected' : '' }>${ wp.i18n.__( 'No', 'woocommerce' ) }</option><option value="yes" ${ enabled === 'yes' ? 'selected' : '' }>${ wp.i18n.__( 'Yes', 'woocommerce' ) }</option></select></fieldset></td></tr><tr valign="top"><th scope="row" class="titledesc"><label>${ wp.i18n.__( 'Name', 'woocommerce' ) }</label></th><td class="forminp"><fieldset><legend class="screen-reader-text"><span>${ wp.i18n.__( 'Name', 'woocommerce' ) }</span></legend><input type="text" class="input-text regular-input ignite-custom-field-name required-field" value="${ name }" style="width: 100%;" name="${ field_key }[${ index }][name]" maxlength="100"/></fieldset></td></tr><tr valign="top"><th scope="row" class="titledesc"><label>${ wp.i18n.__( 'Data', 'woocommerce' ) }</label></th><td class="forminp"><fieldset><legend class="screen-reader-text"><span>${ wp.i18n.__( 'Data', 'woocommerce' ) }</span></legend><input type="text" class="input-text regular-input ignite-custom-field-data required-field" value="${ data_value }" style="width: 100%;" name="${ field_key }[${ index }][data]" maxlength="100"/></fieldset></td></tr></table><div class="remove_custom_field dashicons dashicons-trash" data-index="${ index }"></div></div>`;};igniteCustomFields.prototype.init_tiptip = function () {$( '.woocommerce-help-tip' ).tipTip( {attribute: 'data-tip',fadeIn: 50,fadeOut: 50,delay: 200,keepAlive: true,} );};$( document ).ready( function () {// Only initialize if we're on the custom fields tabif ( $( '#ignite-custom-fields-wrapper' ).length ) {new igniteCustomFields();}} );} )( jQuery );